861:     /**
862:      * Create a produce request from the given record batches
863:      */
864:     private void sendProduceRequest(long now, int destination, short acks, int timeout, List<ProducerBatch> batches) {
865:         if (batches.isEmpty())
866:             return;
867: 
868:         final Map<TopicPartition, ProducerBatch> recordsByPartition = new HashMap<>(batches.size());
869:         Map<String, Uuid> topicIds = topicIdsForBatches(batches);
870: 
871:         ProduceRequestData.TopicProduceDataCollection tpd = new ProduceRequestData.TopicProduceDataCollection();
872:         for (ProducerBatch batch : batches) {
873:             TopicPartition tp = batch.topicPartition;
874:             MemoryRecords records = batch.records();
875:             Uuid topicId = topicIds.get(tp.topic());
876:             ProduceRequestData.TopicProduceData tpData = tpd.find(tp.topic(), topicId);
877: 
878:             if (tpData == null) {
879:                 tpData = new ProduceRequestData.TopicProduceData()
880:                         .setTopicId(topicId).setName(tp.topic());
881:                 tpd.add(tpData);
882:             }
883: 
884:             tpData.partitionData().add(new ProduceRequestData.PartitionProduceData()
885:                     .setIndex(tp.partition())
886:                     .setRecords(records));
887:             recordsByPartition.put(tp, batch);
888:         }
889: 
890:         String transactionalId = null;
891:         boolean useTransactionV1Version = false;
892:         if (transactionManager != null && transactionManager.isTransactional()) {
893:             transactionalId = transactionManager.transactionalId();
894:             useTransactionV1Version = !transactionManager.isTransactionV2Enabled();
895:         }
896: 
897:         ProduceRequest.Builder requestBuilder = ProduceRequest.builder(
898:                 new ProduceRequestData()
899:                         .setAcks(acks)
900:                         .setTimeoutMs(timeout)
901:                         .setTransactionalId(transactionalId)
902:                         .setTopicData(tpd),
903:                 useTransactionV1Version
904:         );
905:         // Fetch topic names from metadata outside callback as topic ids may change during the callback
906:         // for example if topic was recreated.
907:         Map<Uuid, String> topicNames = metadata.topicNames();
908: 
909:         RequestCompletionHandler callback = response -> handleProduceResponse(response, recordsByPartition, topicNames, time.milliseconds());
910: 
911:         String nodeId = Integer.toString(destination);
912:         ClientRequest clientRequest = client.newClientRequest(nodeId, requestBuilder, now, acks != 0,
913:                 requestTimeoutMs, callback);
914:         client.send(clientRequest, now);
915:         log.trace("Sent produce request to {}: {}", nodeId, requestBuilder);
916:     }
