551:     private void doSend(ClientRequest clientRequest, boolean isInternalRequest, long now) {
552:         ensureActive();
553:         String nodeId = clientRequest.destination();
554:         if (!isInternalRequest) {
555:             // If this request came from outside the NetworkClient, validate
556:             // that we can send data.  If the request is internal, we trust
557:             // that internal code has done this validation.  Validation
558:             // will be slightly different for some internal requests (for
559:             // example, ApiVersionsRequests can be sent prior to being in
560:             // READY state.)
561:             if (!canSendRequest(nodeId, now))
562:                 throw new IllegalStateException("Attempt to send a request to node " + nodeId + " which is not ready.");
563:         }
564:         AbstractRequest.Builder<?> builder = clientRequest.requestBuilder();
565:         try {
566:             NodeApiVersions versionInfo = apiVersions.get(nodeId);
567:             short version;
568:             // Note: if versionInfo is null, we have no server version information. This would be
569:             // the case when sending the initial ApiVersionRequest which fetches the version
570:             // information itself.  It is also the case when discoverBrokerVersions is set to false.
571:             if (versionInfo == null) {
572:                 version = builder.latestAllowedVersion();
573:                 if (discoverBrokerVersions && log.isTraceEnabled())
574:                     log.trace("No version information found when sending {} with correlation id {} to node {}. " +
575:                             "Assuming version {}.", clientRequest.apiKey(), clientRequest.correlationId(), nodeId, version);
576:             } else {
577:                 version = versionInfo.latestUsableVersion(clientRequest.apiKey(), builder.oldestAllowedVersion(),
578:                         builder.latestAllowedVersion());
579:             }
580:             // The call to build may also throw UnsupportedVersionException, if there are essential
581:             // fields that cannot be represented in the chosen version.
582:             doSend(clientRequest, isInternalRequest, now, builder.build(version));
583:         } catch (UnsupportedVersionException unsupportedVersionException) {
584:             // If the version is not supported, skip sending the request over the wire.
585:             // Instead, simply add it to the local queue of aborted requests.
586:             log.debug("Version mismatch when attempting to send {} with correlation id {} to {}", builder,
587:                     clientRequest.correlationId(), clientRequest.destination(), unsupportedVersionException);
588:             ClientResponse clientResponse = new ClientResponse(clientRequest.makeHeader(builder.latestAllowedVersion()),
589:                     clientRequest.callback(), clientRequest.destination(), now, now,
590:                     false, unsupportedVersionException, null, null);
591: 
592:             if (!isInternalRequest)
593:                 abortedSends.add(clientResponse);
594:             else if (clientRequest.apiKey() == ApiKeys.METADATA)
595:                 metadataUpdater.handleFailedRequest(now, Optional.of(unsupportedVersionException));
596:             else if (isTelemetryApi(clientRequest.apiKey()) && telemetrySender != null)
597:                 telemetrySender.handleFailedRequest(clientRequest.apiKey(), unsupportedVersionException);
598:         }
599:     }
